mapper.select:
SELECT e.employee_id, e.employee_name AS name, e.employee_tier AS current_tier, e.employee_role AS role, CASE WHEN d.is_deleted = true THEN '임시 발령 대기' WHEN pd.is_deleted = true THEN '임시 발령 대기' ELSE COALESCE(pd.department_name, d.department_name) END AS department_name, CASE WHEN d.is_deleted = true THEN '임시 발령 대기' ELSE d.team_name END AS team_name FROM employee e LEFT JOIN department d ON e.department_id = d.department_id LEFT JOIN department pd ON d.parent_department_id = pd.department_id
AND (d.is_deleted = false OR d.is_deleted IS NULL) AND ( (d.parent_department_id IS NOT NULL AND pd.department_id = #{departmentId}) OR (d.parent_department_id IS NULL AND d.department_id = #{departmentId}) )
AND (d.is_deleted = false OR d.is_deleted IS NULL) AND e.department_id = #{teamId}
AND e.employee_name LIKE CONCAT('%', #{keyword}, '%')
ORDER BY e.employee_id LIMIT #{size} OFFSET #{offset}
